final:
module priority_arbiter(  
    input wire [3:0] deny,  
    output reg [3:0] grant  
);  
    always @(*) begin  
        grant = 4'b0000;  
        if (deny[0]) grant = 4'b0001;  
        else if (deny[1]) grant = 4'b0010;  
        else if (deny[2]) grant = 4'b0100;  
        else if (deny[3]) grant = 4'b1000;  
    end  
endmodule
